file.content:
.streak-milestone-toast {
    position: sticky;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 999;
    background: linear-gradient(135deg, rgba(245, 158, 11, 0.15), rgba(239, 68, 68, 0.1));
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid rgba(245, 158, 11, 0.3);
    border-radius: 16px;
    padding: 16px 24px;
    cursor: pointer;
    overflow: hidden;
    min-width: 280px;
    box-shadow: 0 8px 32px rgba(245, 158, 11, 0.2);
}

.streak-milestone-confetti {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 100%;
    pointer-events: none;
    overflow: hidden;
}

.confetti-piece {
    position: absolute;
    top: -8px;
    width: 6px;
    height: 6px;
    border-radius: 2px;
}

.streak-milestone-content {
    display: flex;
    align-items: center;
    gap: 12px;
    position: relative;
    z-index: 1;
}

.streak-milestone-flame {
    display: flex;
    filter: drop-shadow(0 0 8px rgba(234, 179, 8, 0.6));
    animation: streak-sparkle 2s ease-in-out infinite;
}

.streak-milestone-text {
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.streak-milestone-count {
    font-weight: 700;
    font-size: 16px;
    color: #eab308;
    text-shadow: 0 0 8px rgba(234, 179, 8, 0.4);
}

.streak-milestone-msg {
    font-size: 13px;
    color: var(--text-secondary, #a1a1aa);
}

/* Freeze-used toast */
.streak-freeze-toast {
    position: sticky;
    bottom: 24px;
    left: 50%;
    transform: translateX(-50%);
    z-index: 999;
    display: flex;
    align-items: center;
    gap: 10px;
    background: linear-gradient(135deg, rgba(96, 165, 250, 0.15), rgba(59, 130, 246, 0.1));
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    border: 1px solid rgba(96, 165, 250, 0.3);
    border-radius: 16px;
    padding: 14px 22px;
    cursor: pointer;
    min-width: 260px;
    box-shadow: 0 8px 32px rgba(96, 165, 250, 0.2);
}

